const itemService = require('../services/itemService');

exports.listItems = async (req, res) => {
  try {
    const items = await itemService.getAllItems();
    res.json({ ok: true, items });
  } catch (err) {
    console.error('itemController.listItems error:', err.message);
    res.status(500).json({ ok: false, error: err.message });
  }
};

exports.getItem = async (req, res) => {
  try {
    const item = await itemService.getItemById(req.params.id);
    if (!item) return res.status(404).json({ ok: false, error: 'Item not found' });
    res.json({ ok: true, item });
  } catch (err) {
    console.error('itemController.getItem error:', err.message);
    res.status(500).json({ ok: false, error: err.message });
  }
};

exports.createItem = async (req, res) => {
  try {
    const { name, description } = req.body;
    if (!name) return res.status(400).json({ ok: false, error: 'name is required' });
    const item = await itemService.createItem({ name, description });
    res.status(201).json({ ok: true, item });
  } catch (err) {
    console.error('itemController.createItem error:', err.message);
    res.status(500).json({ ok: false, error: err.message });
  }
};
